1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	
4	interface Item {
5	  type: string;
6	}
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	interface Scenario {
12	  customer: { yearsWithMHPCO: number };
13	  steps: QuoteStep[];
14	}
15	
16	const BASE_PREMIUM: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	};
21	
22	// Rounds up in MHPCO's favor; integer arithmetic avoids IEEE 754 drift.
23	const applyPercentSurchargeRoundedUp = (base: number, percent: number): number =>
24	  Math.ceil((base * (100 + percent)) / 100);
25	
26	const quotePremium = (step: QuoteStep): number => {
27	  if (step.items.length === 0) return PROCESSING_FEE;
28	  const itemBase = BASE_PREMIUM[step.items[0].type];
29	  const withFirstInsurance = applyPercentSurchargeRoundedUp(itemBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
30	  return withFirstInsurance + PROCESSING_FEE;
31	};
32	
33	export const processScenario = (scenario: Scenario): unknown => {
34	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
35	  return { results };
36	};
